const parts = String(msg.topic || '').split('/');
const p = msg.payload;
if (parts.length < 4 || parts[0] !== 'unisadiem' || parts[1] !== 'smartshirt' || !p || typeof p !== 'object') {
    node.warn(`Pacchetto smart shirt non valido su ${msg.topic}`);
    return [null, null, null, null, null];
}

const deviceId = parts[2];
const packetType = parts.slice(3).join('_').toUpperCase();
const patientId = env.get('SMARTSHIRT_PATIENT_ID') || 'patient-demo-001';
const receivedAt = Date.now();
const envelope = {
    ...p,
    device_id: deviceId,
    patient_id: patientId,
    packet_type: packetType,
    source_topic: msg.topic,
    source_timestamp: p.timestamp ?? null,
    gateway_received_at: receivedAt,
    quality: 'measured'
};

const rawMsg = {
    topic: `smartback/shirt/raw/${deviceId}/${packetType.toLowerCase()}`,
    payload: envelope,
    qos: 1,
    retain: false
};

const escapedJson = JSON.stringify(envelope).replace(/\\/g, '\\\\').replace(/"/g, '\\"');
const safeDevice = deviceId.replace(/[ ,=]/g, '_');
const safeType = packetType.replace(/[ ,=]/g, '_');
const influxMsg = {
    method: 'POST',
    url: `${env.get('INFLUXDB_URL')}/api/v2/write?org=${encodeURIComponent(env.get('INFLUXDB_ORG'))}&bucket=${encodeURIComponent(env.get('INFLUXDB_BUCKET'))}&precision=ms`,
    headers: {
        Authorization: `Token ${env.get('INFLUXDB_TOKEN')}`,
        'Content-Type': 'text/plain; charset=utf-8'
    },
    payload: `shirt_raw,device_id=${safeDevice},packet_type=${safeType} payload_json="${escapedJson}" ${receivedAt}`
};

let postureMsg = null;
let deviceMsg = null;
let alertMsg = null;
if (packetType === 'ACC_GYRO' || p.type === 'accgyro') {
    if (!Array.isArray(p.samples) || p.samples.length === 0) {
        node.warn(`ACC_GYRO senza campioni da ${deviceId}`);
    } else {
        const valid = p.samples.filter(s => s && ['x', 'y', 'z'].every(axis => Number.isFinite(Number(s[axis]))));
        if (valid.length > 0) {
            const mean = axis => valid.reduce((sum, sample) => sum + Number(sample[axis]), 0) / valid.length;
            const mx = mean('x');
            const my = mean('y');
            const mz = mean('z');
            const magnitude = Math.sqrt(mx * mx + my * my + mz * mz);
            if (magnitude > 0) {
                postureMsg = {
                    topic: 'smartback/normalized/posture',
                    qos: 1,
                    retain: false,
                    payload: {
                        schema_version: 1,
                        device_id: deviceId,
                        patient_id: patientId,
                        timestamp: receivedAt,
                        sequence: Number(p.samplenum || 0),
                        type: 'accgyro',
                        sampling_frequency: Number(p.sampling_frequency || 0),
                        x: mx / magnitude,
                        y: my / magnitude,
                        z: mz / magnitude,
                        quality: 'measured',
                        source_topic: msg.topic,
                        source_timestamp: p.timestamp ?? null,
                        sample_count: valid.length,
                        orientation: p.orientation ?? null
                    }
                };
            }
        }
    }
} else if (packetType === 'BATTERY_INFO' || p.type === 'battery') {
    const soc = Number(p.state_of_charge);
    if (Number.isFinite(soc)) {
        const boundedSoc = Math.max(0, Math.min(100, soc));
        deviceMsg = {
            topic: 'smartback/normalized/device',
            qos: 1,
            retain: true,
            payload: {
                schema_version: 1,
                device_id: deviceId,
                patient_id: patientId,
                timestamp: receivedAt,
                type: 'battery',
                state_of_charge: boundedSoc,
                charging: Boolean(Number(p.charging)),
                quality: 'measured',
                source_topic: msg.topic,
                source_timestamp: p.timestamp ?? null,
                voltage: p.voltage ?? null,
                temperature: p.temperature ?? null
            }
        };
        const batteryStates = context.get('batteryStates') || {};
        const nextState = boundedSoc <= 10 ? 'critical' : boundedSoc <= 20 ? 'warning' : null;
        const previousState = batteryStates[deviceId] || null;
        if (nextState !== previousState) {
            alertMsg = {
                topic: 'smartback/alerts/device', qos: 1, retain: false,
                payload: {
                    schema_version: 1, timestamp: receivedAt, device_id: deviceId, patient_id: patientId,
                    category: 'device', severity: nextState || 'info', code: nextState === 'critical' ? 'BATTERY_CRITICAL' : nextState === 'warning' ? 'BATTERY_LOW' : 'BATTERY_RECOVERED',
                    message: nextState === 'critical' ? `Batteria critica: ${boundedSoc}%` : nextState === 'warning' ? `Batteria bassa: ${boundedSoc}%` : `Batteria ripristinata: ${boundedSoc}%`,
                    active: nextState !== null, state_of_charge: boundedSoc
                }
            };
            batteryStates[deviceId] = nextState;
            context.set('batteryStates', batteryStates);
        }
    }
} else if (packetType === 'DATALOSS' || p.type === 'dataloss') {
    alertMsg = {
        topic: 'smartback/alerts/device', qos: 1, retain: false,
        payload: {
            schema_version: 1, timestamp: receivedAt, device_id: deviceId, patient_id: patientId,
            category: 'data_quality', severity: 'warning', code: 'DATA_LOSS',
            message: `Perdita dati segnalata dalla maglia: ${p.value ?? 'valore non disponibile'}`,
            active: true, value: p.value ?? null
        }
    };
}

return [rawMsg, postureMsg, deviceMsg, influxMsg, alertMsg];

const a = msg.payload;
if (!a || !a.device_id || !a.code || !Number.isFinite(Number(a.timestamp))) {
    node.warn(`Alert non valido da ${msg.topic}`);
    return [null, null];
}
const safe = value => String(value ?? 'unknown').replace(/[ ,=]/g, '_');
const escapedMessage = String(a.message || a.code).replace(/\\/g, '\\\\').replace(/"/g, '\\"');
const influxMsg = {
    method: 'POST',
    url: `${env.get('INFLUXDB_URL')}/api/v2/write?org=${encodeURIComponent(env.get('INFLUXDB_ORG'))}&bucket=${encodeURIComponent(env.get('INFLUXDB_BUCKET'))}&precision=ms`,
    headers: {Authorization: `Token ${env.get('INFLUXDB_TOKEN')}`, 'Content-Type': 'text/plain; charset=utf-8'},
    payload: `alerts,device_id=${safe(a.device_id)},patient_id=${safe(a.patient_id)},category=${safe(a.category)},severity=${safe(a.severity)},code=${safe(a.code)} active=${Boolean(a.active)},message="${escapedMessage}" ${Number(a.timestamp)}`
};
const debugMsg = {...msg, payload: {...a, received_by_nodered_at: Date.now()}};
return [influxMsg, debugMsg];

const p = msg.payload;
if (!p || !p.device_id || !Number.isFinite(Number(p.timestamp)) || !Number.isFinite(Number(p.state_of_charge))) return null;
const safe = value => String(value).replace(/[ ,=]/g, '_');
msg.method = 'POST';
msg.url = `${env.get('INFLUXDB_URL')}/api/v2/write?org=${encodeURIComponent(env.get('INFLUXDB_ORG'))}&bucket=${encodeURIComponent(env.get('INFLUXDB_BUCKET'))}&precision=ms`;
msg.headers = {Authorization: `Token ${env.get('INFLUXDB_TOKEN')}`, 'Content-Type': 'text/plain; charset=utf-8'};
msg.payload = `device_status,device_id=${safe(p.device_id)},patient_id=${safe(p.patient_id)} state_of_charge=${Number(p.state_of_charge)},charging=${Boolean(p.charging)} ${Number(p.timestamp)}`;
return msg;
